#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
int n;const int N=1010;int u[N],v[N],top1,top2;bool vis[N][N];
struct Pair{int x,y;inline Pair(const int &xx=0,const int &yy=0){x=xx;y=yy;}}ans1[N<<4],ans2[N<<4];
inline bool Jud(){rep(2,n,i)if(!vis[1][i])return true;return false;}
inline void Rev(const int &x)
{
	int a[2],p=0;rep(1,n,i)if(i!=u[x]&&i!=v[x]&&vis[u[x]][i]&&vis[v[x]][i])a[p++]=i;
	vis[u[x]][v[x]]=vis[v[x]][u[x]]=false;vis[u[x]=a[0]][v[x]=a[1]]=vis[a[1]][a[0]]=true;
}
inline void Solve1()
{
	rep(2,n,i)vis[i][i-1]=vis[i-1][i]=true;vis[1][n]=vis[n][1]=true;
	rep(1,n-3,i)u[i]=read(),v[i]=read(),vis[u[i]][v[i]]=vis[v[i]][u[i]]=true;
	while(Jud())
	{
		rep(1,n-3,i)if(u[i]!=1&&v[i]!=1)
		{
			ans1[++top1]=Pair(u[i],v[i]);Rev(i);
			if(u[i]!=1&&v[i]!=1)Rev(i),--top1;
		}
	}
}
inline void Solve2()
{
	memset(vis,false,sizeof(vis));
	rep(2,n,i)vis[i][i-1]=vis[i-1][i]=true;vis[1][n]=vis[n][1]=true;
	rep(1,n-3,i)u[i]=read(),v[i]=read(),vis[u[i]][v[i]]=vis[v[i]][u[i]]=true;
	while(Jud())
	{
		rep(1,n-3,i)if(u[i]!=1&&v[i]!=1)
		{
			Rev(i);if(u[i]!=1&&v[i]!=1)Rev(i);
			else ans2[++top2]=Pair(u[i],v[i]);
		}
	}
}
int main()
{
	n=read();Solve1();Solve2();
	printf("%d\n",top1+top2);rep(1,top1,i)printf("%d %d\n",ans1[i].x,ans1[i].y);
	drep(top2,1,i)printf("%d %d\n",ans2[i].x,ans2[i].y);return 0;
}
